/**
 * AILabel
 *
 * A small, transparent label indicating that adjacent content was
 * generated by the AI synthesis engine. Supports the privacy
 * requirement that users understand what is being synthesized.
 */

interface AILabelProps {
  cached?: boolean;
  className?: string;
}

const AI_DESCRIPTION =
  "Generated by Moontuner's reflective synthesis engine based on your activity record.";

export function AILabel({ cached = false, className = '' }: AILabelProps) {
  return (
    <span
      className={`inline-flex items-center gap-1.5 text-[0.55rem] tracking-[0.2em] uppercase font-sans ${className}`}
      aria-label={AI_DESCRIPTION}
      role="note"
      style={{ color: 'hsl(38 90% 58% / 0.45)' }}
    >
      <span
        className="inline-block w-1 h-1 rounded-full"
        aria-hidden="true"
        style={{ background: 'hsl(38 90% 58% / 0.4)' }}
      />
      AI synthesis{cached ? ' · cached' : ''}
      <span className="sr-only"> — {AI_DESCRIPTION}</span>
    </span>
  );
}
